INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'Which of the following Articles of the Indian Constitution provides for ''protection of monuments and places and objects of national importance''?', 'Article 35', 'Article 39', 'Article 45', 'Article 49', 4, 'Article 49 of the Indian Constitution provides for the protection of monuments, places, and objects of national importance.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'Article 29 of the Indian Constitution provides for which of the following?', 'Protection in respect of conviction for offences', 'Protection of interests of minorities', 'Right against discrimination', 'Protection of certain rights regarding freedom of speech', 2, 'Article 29 protects the interests of minorities, including the right to conserve their language, script, and culture.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'Which of the following pairs of ''Article – provision'' is/are correctly matched as per the context of the Indian Constitution? I. Article 5 - Citizenship at the commencement of the Constitution. II. Article 10 - Rights of citizenship of certain persons of Indian origin residing outside India.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Article 5 deals with citizenship at the commencement of the Constitution (correct). Article 10 deals with continuance of citizenship, not persons residing outside India (Article 8 deals with that). So Only I is correct.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'As of August 2023, which of the following states in India does NOT have a bicameral legislature?', 'Karnataka', 'Andhra Pradesh', 'Bihar', 'West Bengal', 4, 'West Bengal has a unicameral legislature (only Legislative Assembly). Karnataka, Andhra Pradesh, and Bihar have bicameral legislatures.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'In India, the Governor of a State is appointed by the ______.', 'Prime Minister', 'President', 'Council of Ministers', 'Vice President', 2, 'The Governor of a State is appointed by the President of India under Article 155 of the Constitution.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'The ______ acts as the ex-officio Chairman of the Rajya Sabha.', 'President', 'Vice President', 'Prime Minister', 'Comptroller and Auditor General', 2, 'The Vice President of India is the ex-officio Chairman of the Rajya Sabha, as per Article 64 of the Constitution.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'If the court finds that a person is holding office but is not entitled to hold that office, it issues the writ of ______.', 'quo warranto', 'habeas corpus', 'mandamus', 'certiorari', 1, 'The writ of quo warranto (''by what authority'') is used to question the legality of a person holding a public office.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'Which of the following states have more than 30 Lok Sabha constituencies? I. West Bengal II. Madhya Pradesh', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'West Bengal has 42 Lok Sabha constituencies (more than 30). Madhya Pradesh has 29 (less than 30). So Only I is correct.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'Which of the following subjects is included in the Union list in the Indian Constitution? I. Forests II. Defence', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 2, 'Defence is included in the Union List (List I). Forests are in the Concurrent List (List III). So Only II is correct.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding the powers of the Lok Sabha? I. It can Introduce and enact money and non-money bills. II. It can give the Union parliament power to make laws on matters included in the State list.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Lok Sabha can introduce and enact all types of bills (Statement I correct). Statement II is incorrect; only Rajya Sabha can, with special majority, empower Parliament to make laws on State List subjects under Article 249.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'Which Schedule of the Indian Constitution is related to ''powers, authority and responsibilities of Panchayats''?', 'Ninth', 'Tenth', 'Eleventh', 'Twelfth', 3, 'The Eleventh Schedule (Article 243G) lists the powers, authority, and responsibilities of Panchayats in India.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'The Constitutional amendments assigned ______ subjects to the local governments.', '16', '19', '24', '29', 4, 'The 73rd and 74th Constitutional Amendments assigned 29 subjects to the local governments (Panchayats - 29 subjects in 11th Schedule).', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'Which of the following constitutional amendments is about rural local governments?', '72nd Amendment', '73rd Amendment', '74th Amendment', '75th Amendment', 2, 'The 73rd Constitutional Amendment Act, 1992, provides for Panchayati Raj institutions (rural local governments).', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'Which Article of the Indian Constitution is related to ''powers, authority and responsibilities of Municipalities, etc.''?', 'Article 243C', 'Article 243G', 'Article 243S', 'Article 243W', 4, 'Article 243W deals with the powers, authority, and responsibilities of Municipalities under the 74th Amendment.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding local government? I. Local government is government at the village and district level. II. It is convenient for the people to approach the local government for solving their problems both quickly and with minimum cost.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: local government operates at village and district levels, and provides quick, cost-effective solutions to local problems.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '13bcf297-a2d4-4044-adfe-c24a66531e41'::uuid, 2023, 'Paper-I', 'Tantia Tope was killed in ______.', '1857', '1858', '1859', '1860', 3, 'Tantia Tope (Ramachandra Pandurang Tope), a key leader of the 1857 revolt, was executed on 18 April 1859.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '13bcf297-a2d4-4044-adfe-c24a66531e41'::uuid, 2023, 'Paper-I', 'Who was the Nawab of Bengal during the Battle of Plassey?', 'Murshid Quli Khan', 'Alivardi Khan', 'Mir Qasim', 'Sirajuddaulah', 4, 'Sirajuddaulah was the Nawab of Bengal during the Battle of Plassey (1757), which was fought against the British East India Company.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '13bcf297-a2d4-4044-adfe-c24a66531e41'::uuid, 2023, 'Paper-I', 'The Vernacular Press Act was enacted in ______.', '1876', '1877', '1878', '1879', 3, 'The Vernacular Press Act was enacted in 1878 by Lord Lytton to restrict the freedom of the Indian-language press.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '13bcf297-a2d4-4044-adfe-c24a66531e41'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding the origins of the Indian National Congress? I. It was established on 28th December 1885. II. Allan Octavian Hume played a key role in its establishment.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: INC was founded on December 28, 1885, and A.O. Hume played a key role in its formation.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '13bcf297-a2d4-4044-adfe-c24a66531e41'::uuid, 2023, 'Paper-I', 'Which of the following pairs of ''organisation - year of formation'' is/are correctly matched? I. Indian Industrial and Commercial Congress - 1917 II. Federation of the Indian Chamber of Commerce and Industries - 1927', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both are correct: Indian Industrial and Commercial Congress was established in 1917, and FICCI was established in 1927.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '13bcf297-a2d4-4044-adfe-c24a66531e41'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding the Brahmo Samaj? I. It prohibited all forms of idolatry and sacrifice. II. It forbade its members from criticising other religious practices.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Brahmo Samaj prohibited idolatry and sacrifices (Statement I correct). It did not forbid criticism of other religious practices (Statement II incorrect). So Only I is correct.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '13bcf297-a2d4-4044-adfe-c24a66531e41'::uuid, 2023, 'Paper-I', 'Who established the Indian Statistical Institute (ISI) in Calcutta?', 'M.S. Swaminathan', 'P.C. Mahalanobis', 'C.R. Rao', 'D.R. Kaprekar', 2, 'P.C. Mahalanobis established the Indian Statistical Institute (ISI) in Calcutta (Kolkata) in 1931.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '13bcf297-a2d4-4044-adfe-c24a66531e41'::uuid, 2023, 'Paper-I', 'The Tata Iron and Steel Company (TISCO) was incorporated in ______.', '1901', '1903', '1905', '1907', 4, 'TISCO (now Tata Steel) was incorporated in 1907 by Jamsetji Tata and was established at Jamshedpur.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '3e74357f-d7ad-4652-8435-eaa0f7cdfef6'::uuid, 2023, 'Paper-I', 'Hill Area Development Programmes were initiated during ______.', 'First Five Year Plan', 'Third Five Year Plan', 'Fourth Five Year Plan', 'Fifth Five Year Plan', 3, 'Hill Area Development Programmes were initiated during the Fourth Five Year Plan (1969-74) to address the developmental needs of hilly regions.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '3e74357f-d7ad-4652-8435-eaa0f7cdfef6'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct in the context of the Green Revolution in India? I. This refers to the large increase in production of foodgrains resulting from the use of high yielding variety (HYV) seeds. II. The use of these seeds required the use of fertilisers and pesticide in the correct quantities as well as regular supply of water.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: Green Revolution involved HYV seeds, and their success required fertilizers, pesticides, and adequate water supply.', 'medium')
